import{_ as o,o as t,c as r,ag as s}from"./chunks/framework.DZKik_R9.js";const p=JSON.parse('{"title":"Modifications pour brancher la solution A/B sur small-webserver","description":"","frontmatter":{},"headers":[],"relativePath":"webserver/abtest-solution-changes.md","filePath":"webserver/abtest-solution-changes.md"}'),a={name:"webserver/abtest-solution-changes.md"};function n(d,e,i,l,c,u){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="modifications-pour-brancher-la-solution-a-b-sur-small-webserver" tabindex="-1">Modifications pour brancher la solution A/B sur <code>small-webserver</code> <a class="header-anchor" href="#modifications-pour-brancher-la-solution-a-b-sur-small-webserver" aria-label="Permalink to &quot;Modifications pour brancher la solution A/B sur `small-webserver`&quot;">​</a></h1><p>Cette page recense, <strong>côté dépôt <code>small-webserver</code></strong>, les ajouts et réglages qui permettent de faire tourner la <strong>solution <code>abtest-solution</code></strong> (campagnes <strong>frontend</strong> et démo <strong>backend</strong>) dans le lab. L’objectif a été de rester <strong>minimal</strong> : pas de duplication du moteur dans ce dépôt, uniquement de l’<strong>intégration</strong> (config, routes, page de démo, robustesse dev).</p><p>Pour les <strong>URLs</strong> et la <strong>démo backend</strong>, voir aussi <a href="./pages-and-urls">Pages et URLs</a> et <a href="./development">Développement et build</a>.</p><hr><h2 id="vue-d-ensemble" tabindex="-1">Vue d’ensemble <a class="header-anchor" href="#vue-d-ensemble" aria-label="Permalink to &quot;Vue d’ensemble&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Axe</th><th>Rôle dans le lab</th></tr></thead><tbody><tr><td><strong>Frontend</strong> (Module Federation)</td><td>Le <strong>host</strong> charge un <strong>remote</strong> exposant <code>AbTestSlot</code>. En dev, <strong><code>apps/host/.env.development</code></strong> pointe par défaut vers le <strong><code>remoteEntry.js</code></strong> du remote <strong><code>abtest-solution</code></strong> (port <strong>5001</strong>, chemin sans préfixe <code>/remote/</code>). Le package <strong><code>@hackathon/abtest-remote</code></strong> (port <strong>5101</strong>, <code>base</code> <strong><code>/remote/</code></strong>) reste un <strong>stub</strong> utilisable en changeant <strong><code>VITE_ABTEST_REMOTE_URL</code></strong>. Les campagnes <strong><code>frontend</code></strong> passent par <strong><code>POST /api/evaluate</code></strong> (URL API côté remote : <code>VITE_ABTEST_API_URL</code>, défaut <strong>5002</strong>).</td></tr><tr><td><strong>Backend</strong> (feature flags)</td><td>Le <strong>serveur Express</strong> appelle <strong><code>POST /api/evaluate</code></strong> sur l’<strong>API</strong> <code>abtest-solution</code>, relaie les <strong>query params de simulation</strong> comme le remote officiel, et une <strong>page React</strong> affiche le résultat (<code>/demo/backend-abtest</code>).</td></tr></tbody></table><p>Prérequis habituels : API <strong><code>abtest-solution</code></strong> (<code>apps/api</code>, port <strong>5002</strong> par défaut) et données <strong><code>abtest-campaigns-segments</code></strong> à jour.</p><hr><h2 id="partie-frontend-module-federation" tabindex="-1">Partie frontend (Module Federation) <a class="header-anchor" href="#partie-frontend-module-federation" aria-label="Permalink to &quot;Partie frontend (Module Federation)&quot;">​</a></h2><h3 id="configuration-vite-du-host" tabindex="-1">Configuration Vite du host <a class="header-anchor" href="#configuration-vite-du-host" aria-label="Permalink to &quot;Configuration Vite du host&quot;">​</a></h3><ul><li><strong><code>apps/host/vite.config.ts</code></strong><ul><li>Remote <strong><code>abtest_remote</code></strong> : <code>entry</code> = <code>VITE_ABTEST_REMOTE_URL</code> ou, à défaut de variable, <strong><code>http://localhost:&lt;VITE_ABTEST_REMOTE_PORT&gt;/remote/remoteEntry.js</code></strong> (aligné sur le <code>base</code> <strong><code>/remote/</code></strong> du stub <strong><code>apps/abtest-remote</code></strong>).</li><li><strong><code>server.proxy</code></strong> : préfixe <strong><code>/api</code></strong> → <strong><code>http://127.0.0.1:&lt;PORT&gt;</code></strong> (<code>PORT</code> du serveur Express, souvent <strong>5000</strong>) pour que les <code>fetch(&quot;/api/...&quot;)</code> depuis le host Vite atteignent le lab Node en dev.</li></ul></li></ul><h3 id="fichiers-d-environnement" tabindex="-1">Fichiers d’environnement <a class="header-anchor" href="#fichiers-d-environnement" aria-label="Permalink to &quot;Fichiers d’environnement&quot;">​</a></h3><ul><li><strong><code>apps/host/.env.development</code></strong> — en pratique, URL du <strong><code>remoteEntry.js</code></strong> du remote <strong><code>abtest-solution</code></strong> (ex. <strong><code>http://localhost:5001/remoteEntry.js</code></strong>). Pour le lab <strong>sans</strong> <code>abtest-solution</code>, repointer vers <strong><code>http://localhost:5101/remote/remoteEntry.js</code></strong>.</li><li><strong><code>.env.example</code></strong> (racine) — rappel de <strong><code>VITE_ABTEST_REMOTE_URL</code></strong> et des variables <strong><code>ABTEST_*</code></strong> pour la démo backend.</li></ul><h3 id="composant-hote-et-resilience" tabindex="-1">Composant hôte et résilience <a class="header-anchor" href="#composant-hote-et-resilience" aria-label="Permalink to &quot;Composant hôte et résilience&quot;">​</a></h3><ul><li><strong><code>apps/host/src/components/AbTestRemoteSlot.tsx</code></strong> — <code>lazy()</code> vers <strong><code>abtest_remote/AbTestSlot</code></strong>, derrière <strong><code>OpenFeature</code></strong> (<code>enable_remote_abtest_shell</code>).</li><li><strong><code>apps/host/src/components/AbTestRemoteSlotErrorBoundary.tsx</code></strong> — si le <strong><code>remoteEntry.js</code></strong> est injoignable (mauvais port, remote arrêté), <strong>erreur localisée</strong> au lieu de faire planter toute l’application React.</li></ul><h3 id="confort-dev" tabindex="-1">Confort dev <a class="header-anchor" href="#confort-dev" aria-label="Permalink to &quot;Confort dev&quot;">​</a></h3><ul><li><strong><code>apps/host/index.html</code></strong> — favicon en <strong>data-URI</strong> pour éviter un <strong>404</strong> systématique sur <code>favicon.ico</code>.</li></ul><h3 id="serveur-node-proxy-dev" tabindex="-1">Serveur Node (proxy dev) <a class="header-anchor" href="#serveur-node-proxy-dev" aria-label="Permalink to &quot;Serveur Node (proxy dev)&quot;">​</a></h3><ul><li><strong><code>server/src/index.ts</code></strong> — compatibilité <strong><code>http-proxy-middleware</code> v3</strong> (<code>on.proxyReq</code>) lorsque le build host n’existe pas encore et que le trafic est proxifié vers Vite.</li></ul><hr><h2 id="partie-backend-evaluation-cote-serveur" tabindex="-1">Partie backend (évaluation côté serveur) <a class="header-anchor" href="#partie-backend-evaluation-cote-serveur" aria-label="Permalink to &quot;Partie backend (évaluation côté serveur)&quot;">​</a></h2><h3 id="route-express" tabindex="-1">Route Express <a class="header-anchor" href="#route-express" aria-label="Permalink to &quot;Route Express&quot;">​</a></h3><ul><li><p><strong><code>server/src/abtestBackendLab.ts</code></strong> (nouveau) — <strong><code>GET /api/lab/backend-abtest</code></strong> :</p><ul><li>cookies de lab (<code>lab_abtest_user_id</code>, <code>lab_ab_assignment_&lt;campaignId&gt;</code>) ;</li><li>appel <strong><code>POST /api/evaluate</code></strong> vers <strong><code>ABTEST_API_URL</code></strong> (défaut <code>http://127.0.0.1:5002</code>) ;</li><li>relais des paramètres <strong><code>ab_campaign_id</code></strong>, <strong><code>ab_simulation</code></strong>, <strong><code>ab_force</code></strong>, <strong><code>ab_variation_id</code></strong>, <strong><code>ab_skip</code></strong> (même logique que le remote <strong><code>AbTestSlot</code></strong> d’<code>abtest-solution</code>) ;</li><li>réponse JSON pour la page démo (dont objet <strong><code>lab</code></strong> pour le debug).</li></ul></li><li><p><strong><code>server/src/index.ts</code></strong> — enregistrement de la route <strong>avant</strong> le static et le proxy catch-all.</p></li></ul><h3 id="page-et-navigation-host" tabindex="-1">Page et navigation host <a class="header-anchor" href="#page-et-navigation-host" aria-label="Permalink to &quot;Page et navigation host&quot;">​</a></h3><ul><li><strong><code>apps/host/src/pages/BackendAbtestDemoPage.tsx</code></strong> — démo <strong><code>/demo/backend-abtest</code></strong> : <code>fetch</code> avec <strong><code>location.search</code></strong>, affichage des <strong>liens de simulation</strong>, fond selon <strong><code>featureFlags</code></strong>.</li><li><strong><code>apps/host/src/App.tsx</code></strong> — route <strong><code>/demo/backend-abtest</code></strong>.</li><li><strong><code>apps/host/src/pages/HomePage.tsx</code></strong> — lien depuis l’accueil.</li></ul><h3 id="documentation-utilisateur-du-lab" tabindex="-1">Documentation utilisateur du lab <a class="header-anchor" href="#documentation-utilisateur-du-lab" aria-label="Permalink to &quot;Documentation utilisateur du lab&quot;">​</a></h3><ul><li><strong><code>README.md</code></strong> — section courte sur la démo backend et les variables d’environnement.</li></ul><hr><h2 id="ce-qui-reste-hors-de-small-webserver" tabindex="-1">Ce qui reste hors de <code>small-webserver</code> <a class="header-anchor" href="#ce-qui-reste-hors-de-small-webserver" aria-label="Permalink to &quot;Ce qui reste hors de `small-webserver`&quot;">​</a></h2><ul><li><strong>Moteur, API, remote officiel, données</strong> : dépôts <strong><code>abtest-solution</code></strong> et <strong><code>abtest-campaigns-segments</code></strong> (voir <a href="./../solution/intro">Solution — introduction</a> et <a href="./../solution/module-federation">Module Federation &amp; hôte</a>).</li></ul><hr><h2 id="voir-aussi" tabindex="-1">Voir aussi <a class="header-anchor" href="#voir-aussi" aria-label="Permalink to &quot;Voir aussi&quot;">​</a></h2><ul><li><a href="./pages-and-urls">Pages et URLs</a> — routes <code>/demo/*</code>, ancre <strong>Démo A/B backend</strong>.</li><li><a href="./development">Développement et build</a> — lancement conjoint API + lab.</li><li><a href="./../reference/ports-and-env#small-webserver">Référence — ports et variables</a>.</li><li><a href="./../reference/api-overview">Aperçu de l’API</a> — <code>POST /api/evaluate</code>.</li></ul>',33)])])}const h=o(a,[["render",n]]);export{p as __pageData,h as default};
